I tried to use bird but it didn't up bgp sessions in fib 1.

bird_enable="YES"
bird_fib="1"

log "/var/log/bird.log" all;
log stderr all;

router id 10.64.244.139;

protocol device { }

protocol kernel {               # Primary routing table
        learn;                  # Learn alien routes from the kernel
        persist;                # Do not remove routes on bird shutdown
        scan time 10;           # Scan kernel routing table every 10 seconds
        kernel table 1;
        ipv4 {
                import all;
                export all;
        };
}

protocol bfd {
        interface "mce*" {
                interval 100 ms;
                min rx interval 100 ms;
                multiplier 5;
        };
}

filter vxlan_fabric {
        if (net ~ [ 172.16.0.0/15{15,16}]) then {
                accept;
        }
}

protocol bgp {
        local as 4230040015;
        neighbor 192.168.255.0 as 4230041240;
        hold 180;
        keepalive 60;
        bfd on;
        ipv4 {
                export filter vxlan_fabric;
                import all;
                next hop self;
        };
}

